SELECT 
  COUNT(*) as active_last_5min
FROM active_sessions
WHERE lastActive > DATE_SUB(NOW(), INTERVAL 5 MINUTE);

SELECT 
  COUNT(*) as active_last_30min,
  SUM(CASE WHEN isGuest = 0 THEN 1 ELSE 0 END) as registered,
  SUM(CASE WHEN isGuest = 1 THEN 1 ELSE 0 END) as guests
FROM active_sessions
WHERE lastActive > DATE_SUB(NOW(), INTERVAL 30 MINUTE);

SELECT COUNT(*) as total_sessions FROM active_sessions;

DESCRIBE puzzle_attempts;

